def run_command(args, *, cwd=None, stdin_path=None):
    stdin_data = None
    if stdin_path is not None:
        stdin_data = stdin_path.read_text()

    return subprocess.run(
        [str(arg) for arg in args],
        cwd=cwd,
        input=stdin_data,
        text=True,
        capture_output=True,
    )


def ensure_repo(path, url):
    if path.exists():
        return

    path.parent.mkdir(parents=True, exist_ok=True)
    result = run_command(["git", "clone", "--depth", "1", url, path])
    if result.returncode != 0:
        print(f"failed to clone {url}", file=sys.stderr)
        print(result.stdout, file=sys.stderr)
        print(result.stderr, file=sys.stderr)
        sys.exit(result.returncode)


def build_interpreter(interpreter_dir):
    result = run_command(["cargo", "build", "--release"], cwd=interpreter_dir)
    if result.returncode != 0:
        print("failed to build interpreter", file=sys.stderr)
        print(result.stdout, file=sys.stderr)
        print(result.stderr, file=sys.stderr)
        sys.exit(result.returncode)

    binary = interpreter_dir / "target" / "release" / "main"
    if not binary.exists():
        print(f"interpreter binary not found: {binary}", file=sys.stderr)
        sys.exit(1)

    return binary


def benchmark_cases(benchmarks_dir):
    for benchmark_dir in sorted(benchmarks_dir.iterdir()):
        if not benchmark_dir.is_dir() or benchmark_dir.name.startswith("."):
            continue

        source = benchmark_dir / "src" / f"{benchmark_dir.name}.ll"
        test_dir = benchmark_dir / "test"
        if not source.exists() or not test_dir.exists():
            continue

        inputs = sorted(test_dir.glob("input*.txt"))
        for input_path in inputs:
            suffix = input_path.stem.removeprefix("input")
            output_path = test_dir / f"output{suffix}.txt"
            if output_path.exists():
                yield benchmark_dir.name, source, input_path, output_path


def compile_benchmark(compiler, source, asm_path):
    asm_path.parent.mkdir(parents=True, exist_ok=True)
    result = run_command([compiler, source, asm_path])
    if result.returncode != 0:
        return False, result
    return True, result


def run_case(interpreter, asm_path, input_path, timeout=None):
    import tempfile, os, types
    cost_file = tempfile.NamedTemporaryFile(delete=False, suffix=".cost")
    cost_file.close()
    with open(input_path) as stdin_file:
        proc = subprocess.Popen(
            [str(interpreter), str(asm_path), cost_file.name],
            stdin=stdin_file, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True
        )
        try:
            stdout, stderr = proc.communicate(timeout=timeout)
            result = types.SimpleNamespace(returncode=proc.returncode, stdout=stdout, stderr=stderr)
        except subprocess.TimeoutExpired:
            proc.kill()
            proc.communicate()
            result = types.SimpleNamespace(returncode=1, stdout="", stderr="TIMEOUT")
    try:
        raw = open(cost_file.name).read().strip()
        # format: "Final Cost : 419"
        result.interpreter_cost = int(raw.split(":")[-1].strip()) if raw else None
    except (FileNotFoundError, OSError, ValueError):
        result.interpreter_cost = None
    if result.stderr == "TIMEOUT":
        result.interpreter_cost = "TIMEOUT"
    try:
        os.unlink(cost_file.name)
    except FileNotFoundError:
        pass
    return result


