def parse_asm_opcode(line):
    line = line.split("#", 1)[0].strip()
    if not line or line.endswith(":"):
        return None

    if "=" in line:
        line = line.split("=", 1)[1].strip()

    if not line:
        return None

    opcode = line.split()[0].lower()
    if opcode in {"start", "end"}:
        return None

    return opcode


def load_cost_model(path):
    default_cost = 1.0
    costs = {}

    if path is None:
        return default_cost, costs

    with path.open() as f:
        data = json.load(f)

    if not isinstance(data, dict):
        raise ValueError("cost model must be a JSON object")

    if "default" in data:
        default_cost = float(data["default"])

    for opcode, cost in data.items():
        if opcode == "default":
            continue
        costs[opcode.lower()] = float(cost)

    return default_cost, costs


def summarize_asm_cost(asm_path, default_cost, costs):
    opcode_counts = Counter()

    for line in asm_path.read_text().splitlines():
        opcode = parse_asm_opcode(line)
        if opcode is not None:
            opcode_counts[opcode] += 1

    estimated_cost = sum(
        count * costs.get(opcode, default_cost)
        for opcode, count in opcode_counts.items()
    )

    return {
        "instructions": sum(opcode_counts.values()),
        "estimated_cost": estimated_cost,
        "opcode_counts": opcode_counts,
    }


